// Open specific package to all modules
module com.example.app {
    opens com.example.app.model;
}

// Open specific package to specific modules only
module com.example.app {
    opens com.example.app.model to com.fasterxml.jackson;
}

// Open entire module
open module com.example.app {
    exports com.example.app.api;
    // All packages are accessible via reflection
}

// Reflection on opened classes
Class<?> clazz = Class.forName("com.example.app.model.User");
Field field = clazz.getDeclaredField("name");
field.setAccessible(true); // Succeeds if opened

